import subprocess, tempfile, os

def segment_resample_audio(file_path, timestamp_list):
    temp_dir = tempfile.mkdtemp()
    temp_file_list = []
    target_sample_rate = 16000
    for i in range(1, len(timestamp_list)):
        relative_filename = f"audio_downscaled_{i}.wav"
        command = [
            "ffmpeg",
            "-ss", str(timestamp_list[i - 1]),
            "-to", str(timestamp_list[i]),
            "-i", file_path,
            "-ac", "1",
            "-ar", str(target_sample_rate),
            "-y", os.path.join(temp_dir, relative_filename),
        ]
        subprocess.run(command, check=True)
        temp_file_list.append(relative_filename)
    return temp_dir, temp_file_list

#this function assumes that there will never be a gap w/o speakers larger than 10min
#AND that pyannote wont spit out an 11-minute-long monologue.
def get_split_timestamps(onset_list, duration_list):
    MAX_FILE_LENGTH_SECONDS = 600
    timestamp_list = [float(0)]
    last_file_start = 0
    
    #when splitting with ffmpeg, t = 0 of each file will be exactly at
    #pyannote's detected start of a new segment
    for i, offset in enumerate(onset_list):
        if (offset - last_file_start > MAX_FILE_LENGTH_SECONDS):
            timestamp_list.append(onset_list[i - 1])
            last_file_start = onset_list[i - 1]
    if (onset_list[-1] != timestamp_list[-1]):
        # basically no cost in just adding one last file
        if (duration_list[-1] > 60.0): # limit for wav is (600 + 60.0 = 780 secs)
            timestamp_list.append(onset_list[-1])
        timestamp_list.append(onset_list[-1] + duration_list[-1])
    return timestamp_list

